I cannot directly render or generate a 3D image file (like a .obj, .fbx, or .png) within this chat interface. However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a popular JavaScript library for 3D graphics in the browser.

You can copy the code below, save it as an `.html` file, and open it in any modern web browser to see the 3D model.

### 3D House Model (Three.js Code)

This code creates a simple house with a roof, walls, a door, and a window using geometric primitives.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Ground
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction
        const houseGroup = new THREE.Group();

        // Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8b4513 }); // Brown roof
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x333333 }); // Dark door
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // Walls
        const wallGeo = new THREE.BoxGeometry(8, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMat);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 4.1); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(2, 2, 0.2);
        const windowMesh = new THREE.Mesh(winGeo, windowMat);
        windowMesh.position.set(0, 5, 4.1);
        houseGroup.add(windowMesh);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        scene.add(houseGroup);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Create a file:** Create a new file on your computer named `house.html`.
2.  **Paste:** Paste the code above into that file and save it.
3.  **Run:** Double-click `house.html` to open it in Chrome, Firefox, or Edge.

### What this code does:
*   **Scene Setup:** Initializes a 3D scene, camera, and renderer.
*   **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts shadows.
*   **Geometry:**
    *   **Walls:** A white cube (`BoxGeometry`).
    *   **Roof:** A pyramid shape (`ConeGeometry`) rotated to sit on top of the walls.
    *   **Door/Window:** Smaller boxes attached to the front of the walls.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.
